svg.script:
var MIN_FLOW=5,nTimer=null,curModal=null,popupWin=null,popupTimer=null;
var diagramTitle='SCULPTEUR DE BUDGET SANKEY';
var isDark=true,isolatedNode=null,legendVisible=false;
var wasDragged=false,mouseSX=0,mouseSY=0;

var darkT={bg:'#0d1117',fg:'#e6edf3',dim:'#8b949e',panel:'#161b22',brd:'#30363d',
barBg:'#21262d',fOp:.35,fAct:.6,fDim:.1,nFill:.18,nStr:.5,hOp:.65,hDim:.1,
eCol:'#fff',eOp:.25,tBg:'#1c2128',tBrd:'#34d39940',lBg:'#161b22',lBgO:.93,gOp:.04,gCol:'#8b949e'};
var lightT={bg:'#f8fafc',fg:'#1e293b',dim:'#64748b',panel:'#ffffff',brd:'#e2e8f0',
barBg:'#e2e8f0',fOp:.42,fAct:.65,fDim:.07,nFill:.22,nStr:.7,hOp:.75,hDim:.07,
eCol:'#334155',eOp:.07,tBg:'#ffffff',tBrd:'#34d39960',lBg:'#ffffff',lBgO:.95,gOp:.06,gCol:'#94a3b8'};
var T=darkT;

var revenues=[
{id:'r1',name:'Impôts sur le revenu',amount:3200,color:'#fbbf24'},
{id:'r2',name:'TVA',amount:2800,color:'#f59e0b'},
{id:'r3',name:'Taxes locales',amount:1200,color:'#d97706'},
{id:'r4',name:'Emprunts',amount:800,color:'#b45309'},
{id:'r5',name:'Subventions État',amount:500,color:'#92400e'}
];
var expenses=[
{id:'e1',name:'Éducation',color:'#34d399',amount:0},
{id:'e2',name:'Santé',color:'#2dd4bf',amount:0},
{id:'e3',name:'Sécurité',color:'#38bdf8',amount:0},
{id:'e4',name:'Infrastructures',color:'#a78bfa',amount:0},
{id:'e5',name:'Culture',color:'#fb923c',amount:0},
{id:'e6',name:'Dette',color:'#f87171',amount:0}
];
var flows=[
{id:'f1',from:'r1',to:'e1',amount:900},{id:'f2',from:'r1',to:'e2',amount:700},
{id:'f3',from:'r1',to:'e3',amount:500},{id:'f4',from:'r1',to:'e4',amount:600},
{id:'f5',from:'r1',to:'e5',amount:250},{id:'f6',from:'r1',to:'e6',amount:250},
{id:'f7',from:'r2',to:'e1',amount:500},{id:'f8',from:'r2',to:'e2',amount:600},
{id:'f9',from:'r2',to:'e3',amount:500},{id:'f10',from:'r2',to:'e4',amount:700},
{id:'f11',from:'r2',to:'e6',amount:500},
{id:'f12',from:'r3',to:'e1',amount:400},{id:'f13',from:'r3',to:'e3',amount:400},
{id:'f14',from:'r3',to:'e4',amount:200},{id:'f15',from:'r3',to:'e5',amount:200},
{id:'f16',from:'r4',to:'e4',amount:400},{id:'f17',from:'r4',to:'e6',amount:300},
{id:'f18',from:'r4',to:'e2',amount:100},
{id:'f19',from:'r5',to:'e5',amount:200},{id:'f20',from:'r5',to:'e1',amount:200},
{id:'f21',from:'r5',to:'e2',amount:100}
];
var initAmts={},initExpT={};
var LX=25,LW=190,RX=1185,RW=190,TOP=82,BOT=710,GAP=5;
var totalBudget=0,SCALE=1;

function gR(id){for(var i=0;i<revenues.length;i++)if(revenues[i].id===id)return revenues[i];return revenues[0];}
    function gE(id){for(var i=0;i<expenses.length;i++)if(expenses[i].id===id)return expenses[i];return expenses[0];}
        function recomp(){
        totalBudget=0;for(var i=0;i<revenues.length;i++)totalBudget+=revenues[i].amount;
            var lu=BOT-TOP-(revenues.length-1)*GAP,ru=BOT-TOP-(expenses.length-1)*GAP;
            SCALE=Math.min(lu,ru)/Math.max(totalBudget,1);
            for(var j=0;j<expenses.length;j++)expenses[j].amount=calcT(expenses[j].id);
                }
                function calcT(eid){var s=0;for(var i=0;i<flows.length;i++)if(flows[i].to===eid)s+=flows[i].amount;return s;}
                    function saveInit(){initAmts={};initExpT={};for(var i=0;i<flows.length;i++)initAmts[flows[i].id]=flows[i].amount;for(var j=0;j<expenses.length;j++)initExpT[expenses[j].id]=expenses[j].amount;}
                            function computeLayout(){
                            recomp();var y=TOP;
                            for(var i=0;i<revenues.length;i++){var r=revenues[i];r.x=LX;r.w=LW;r.y=y;r.h=Math.max(1,r.amount*SCALE);y+=r.h+GAP;}
                                y=TOP;for(var j=0;j<expenses.length;j++){var e=expenses[j];e.x=RX;e.w=RW;e.y=y;e.h=Math.max(1,e.amount*SCALE);y+=e.h+GAP;}
                                    for(var k=0;k<revenues.length;k++){var src=revenues[k],out=[];for(var m=0;m<flows.length;m++)if(flows[m].from===src.id)out.push(flows[m]);
                                            out.sort(function(a,b){return gE(b.to).y-gE(a.to).y;});var off=0;for(var n=0;n<out.length;n++){var f=out[n];f.x0=src.x+src.w;f.y0=src.y+off;f.h=Math.max(.5,f.amount*SCALE);off+=f.h;}}
                                                for(var p=0;p<expenses.length;p++){var tgt=expenses[p],inp=[];for(var q=0;q<flows.length;q++)if(flows[q].to===tgt.id)inp.push(flows[q]);
                                                        inp.sort(function(a,b){return gR(b.from).y-gR(a.from).y;});var off2=0;for(var r2=0;r2<inp.length;r2++){var f2=inp[r2];f2.x1=tgt.x;f2.y1=tgt.y+off2;off2+=f2.h;}}
                                                            }

                                                            function fmt(n){return Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g,' ');}
                                                            function fmtP(n){return(n/totalBudget*100).toFixed(1).replace('.',',')+' %';}
                                                            function esc(s){return String(s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
                                                            function fpD(f){var c=(f.x0+f.x1)/2;return 'M'+f.x0+','+f.y0+' C'+c+','+f.y0+' '+c+','+f.y1+' '+f.x1+','+f.y1+' L'+f.x1+','+(f.y1+f.h)+' C'+c+','+(f.y1+f.h)+' '+c+','+(f.y0+f.h)+' '+f.x0+','+(f.y0+f.h)+' Z';}
                                                            function fpMY(f){return(f.y0+f.y1+f.h)/2;}function fpMX(f){return(f.x0+f.x1)/2;}
                                                            function legN(n){var m={'Impôts sur le revenu':'Impôts rev.','Taxes locales':'Tax. locales','Subventions État':'Subv. État'};return m[n]||n;}
                                                            function flowIsConnected(f){return isolatedNode&&(f.from===isolatedNode||f.to===isolatedNode);}

                                                            var eF,eH,eNL,eNR,eTT,eG,eS,eLeg;

                                                            function render(){
                                                            var h='',isol=!!isolatedNode;
                                                            for(var i=0;i<flows.length;i++){
                                                                var f=flows[i],s=gR(f.from),conn=flowIsConnected(f);
                                                                var o=isol?(conn?T.fAct:T.fDim):(dragF&&dragF!==f.id?T.fDim:(dragF===f.id?T.fAct:T.fOp));
                                                                h+='<path class="flow-path" data-fid="'+f.id+'" d="'+fpD(f)+'" fill="'+s.color+'" opacity="'+o+'"/>';
                                                                var my=f.y0+f.h/2,my1=f.y1+f.h/2,c=(f.x0+f.x1)/2,eo=o*T.eOp;
                                                                h+='<path d="M'+f.x0+','+my+' C'+c+','+my+' '+c+','+my1+' '+f.x1+','+my1+'" fill="none" stroke="'+T.eCol+'" stroke-width=".5" stroke-dasharray="3 12" opacity="'+eo+'"><animate attributeName="stroke-dashoffset" from="15" to="0" dur="1.2s" repeatCount="indefinite"/></path>';
                                                                }eF.innerHTML=h;
                                                                h='';for(var j=0;j<flows.length;j++){
                                                                    var f2=flows[j],mx=fpMX(f2),my2=fpMY(f2),s2=gR(f2.from),conn2=flowIsConnected(f2);
                                                                    var o2=isol?(conn2?T.hOp:T.hDim):(dragF&&dragF!==f2.id?T.hDim:(dragF===f2.id?T.hOp:T.hOp)),sz=f2.h>6?6:4;
                                                                    h+='<g class="handle" data-fid="'+f2.id+'" transform="translate('+mx+','+my2+')" opacity="'+o2+'" filter="url(#glow)"><path d="M0,'+(-sz)+' L'+sz+',0 L0,'+sz+' L'+(-sz)+',0 Z" fill="#fff" stroke="'+s2.color+'" stroke-width="1.5"/></g>';
                                                                    }eH.innerHTML=h;
                                                                    h='';for(var k=0;k<revenues.length;k++){var r=revenues[k],isSel=isolatedNode===r.id;
                                                                        h+='<g class="node-rect" data-nid="'+r.id+'"><rect x="'+r.x+'" y="'+r.y+'" width="'+r.w+'" height="'+r.h+'" rx="4" fill="'+r.color+'" fill-opacity="'+T.nFill+'" stroke="'+r.color+'" stroke-width="'+(isSel?2.5:1.2)+'" stroke-opacity="'+(isSel?1:T.nStr)+'"/>';
                                                                            var fs=r.h>55?11:r.h>38?9.5:8,y1=r.y+r.h/2-(r.h>55?7:0),y2=r.y+r.h/2+(r.h>55?7:0);
                                                                            h+='<text x="'+(r.x+r.w/2)+'" y="'+y1+'" text-anchor="middle" fill="'+r.color+'" font-size="'+fs+'" font-weight="600">'+esc(r.name)+'</text>';
                                                                            if(r.h>55)h+='<text x="'+(r.x+r.w/2)+'" y="'+y2+'" text-anchor="middle" fill="'+T.fg+'" font-size="'+(fs-1)+'" opacity=".8">'+fmt(r.amount)+' M€</text>';
                                                                            h+='</g>';}eNL.innerHTML=h;
                                                                        h='';for(var l=0;l<expenses.length;l++){var e=expenses[l],isSel2=isolatedNode===e.id;
                                                                            h+='<g class="node-rect" data-nid="'+e.id+'"><rect x="'+e.x+'" y="'+e.y+'" width="'+e.w+'" height="'+e.h+'" rx="4" fill="'+e.color+'" fill-opacity="'+T.nFill+'" stroke="'+e.color+'" stroke-width="'+(isSel2?2.5:1.2)+'" stroke-opacity="'+(isSel2?1:T.nStr)+'"/>';
                                                                                var fs2=e.h>55?11:e.h>38?9.5:8,ey1=e.y+e.h/2-(e.h>55?7:0),ey2=e.y+e.h/2+(e.h>55?7:0);
                                                                                h+='<text x="'+(e.x+e.w/2)+'" y="'+ey1+'" text-anchor="middle" fill="'+e.color+'" font-size="'+fs2+'" font-weight="600">'+esc(e.name)+'</text>';
                                                                                if(e.h>55)h+='<text x="'+(e.x+e.w/2)+'" y="'+ey2+'" text-anchor="middle" fill="'+T.fg+'" font-size="'+(fs2-1)+'" opacity=".8">'+fmt(e.amount)+' M€</text>';
                                                                                h+='</g>';}eNR.innerHTML=h;
                                                                            renderSummary();renderLegend();
                                                                            }

                                                                            function renderSummary(){
                                                                            var h='',mx=1;for(var i=0;i<expenses.length;i++)if(expenses[i].amount>mx)mx=expenses[i].amount;var bw=520;
                                                                                for(var j=0;j<expenses.length;j++){
                                                                                    var e=expenses[j],w=Math.max(2,e.amount/mx*bw),d=e.amount-initExpT[e.id],ds=d===0?'':((d>0?'+':'')+fmt(d)),dc=d>0?'#34d399':d<0?'#f87171':'#8b949e',yb=760+j*24;
                                                                                        h+='<g class="summary-row" style="animation-delay:'+(j*80)+'ms"><text x="40" y="'+(yb+10)+'" fill="'+e.color+'" font-size="10.5" font-weight="600">'+esc(e.name)+'</text>';
                                                                                            h+='<rect x="220" y="'+(yb-2)+'" width="'+bw+'" height="13" rx="3" fill="'+T.barBg+'"/>';
                                                                                            h+='<rect x="220" y="'+(yb-2)+'" width="'+w+'" height="13" rx="3" fill="'+e.color+'" fill-opacity=".5"/>';
                                                                                            h+='<rect x="'+(220+w-3)+'" y="'+(yb-2)+'" width="3" height="13" rx="1" fill="'+e.color+'" fill-opacity=".9"/>';
                                                                                            h+='<text x="755" y="'+(yb+10)+'" fill="'+T.fg+'" font-size="10.5" font-weight="500">'+fmt(e.amount)+' M€</text>';
                                                                                            h+='<text x="860" y="'+(yb+10)+'" fill="'+T.dim+'" font-size="9.5">'+fmtP(e.amount)+'</text>';
                                                                                            if(ds)h+='<text x="940" y="'+(yb+10)+'" fill="'+dc+'" font-size="9.5" font-weight="600">'+ds+'</text>';h+='</g>';}
                                                                                        var ty=760+6*24+3,te=0;for(var m=0;m<expenses.length;m++)te+=expenses[m].amount;
                                                                                            var sol=totalBudget-te,sc=Math.abs(sol)<1?'#34d399':'#f87171';
                                                                                                h+='<line x1="40" y1="'+ty+'" x2="1360" y2="'+ty+'" stroke="'+T.brd+'" stroke-width=".5"/>';
                                                                                                h+='<text x="40" y="'+(ty+15)+'" fill="#f0b429" font-size="11" font-weight="700">TOTAL DÉPENSES</text>';
                                                                                                h+='<text x="755" y="'+(ty+15)+'" fill="#f0b429" font-size="11" font-weight="700">'+fmt(te)+' M€</text>';
                                                                                                h+='<text x="860" y="'+(ty+15)+'" fill="#f0b429" font-size="10" font-weight="600">'+fmtP(te)+'</text>';
                                                                                                h+='<text x="1080" y="'+(ty+15)+'" fill="'+sc+'" font-size="11" font-weight="700">SOLDE : '+(sol>=0?'+':'')+fmt(sol)+' M€</text>';
                                                                                                eS.innerHTML=h;
                                                                                                }

                                                                                                function renderLegend(){
                                                                                                if(!legendVisible){eLeg.setAttribute('opacity','0');eLeg.style.pointerEvents='none';return;}
                                                                                                eLeg.setAttribute('opacity','1');eLeg.style.pointerEvents='all';
                                                                                                var items=[],isol=!!isolatedNode;
                                                                                                for(var i=0;i<revenues.length;i++)items.push({n:legN(revenues[i].name),c:revenues[i].color,id:revenues[i].id});
                                                                                                    for(var j=0;j<expenses.length;j++)items.push({n:legN(expenses[j].name),c:expenses[j].color,id:expenses[j].id});
                                                                                                        var h='<rect x="25" y="680" width="1350" height="26" rx="6" fill="'+T.lBg+'" fill-opacity="'+T.lBgO+'" stroke="'+T.brd+'" stroke-width=".5"/>';
                                                                                                        var x=40;
                                                                                                        for(var k=0;k<items.length;k++){
                                                                                                            var it=items[k],isSel=isolatedNode===it.id,op=isol?(isSel?1:.2):.85;
                                                                                                            h+='<g class="leg-item" data-nid="'+it.id+'" opacity="'+op+'">';
                                                                                                                h+='<circle cx="'+(x+5)+'" cy="693" r="5" fill="'+it.c+'"'+(isSel?' stroke="#fff" stroke-width="1.5"':'')+'/>';
                                                                                                                h+='<text x="'+(x+14)+'" y="697" fill="'+T.fg+'" font-size="9" font-weight="500" opacity="'+op+'">'+esc(it.n)+'</text></g>';
                                                                                                            x+=it.n.length*5.8+24;
                                                                                                            }
                                                                                                            eLeg.innerHTML=h;
                                                                                                            }

                                                                                                            function applyTheme(){
                                                                                                            document.getElementById('bgRect').setAttribute('fill',T.bg);
                                                                                                            document.getElementById('mainTitle').setAttribute('fill',T.fg);
                                                                                                            document.getElementById('subTitle').setAttribute('fill',T.dim);
                                                                                                            document.getElementById('sumPanel').setAttribute('fill',T.panel);
                                                                                                            document.getElementById('sumPanel').setAttribute('stroke',T.brd);
                                                                                                            document.getElementById('sumTitle').setAttribute('fill',T.dim);
                                                                                                            document.getElementById('sumLine').setAttribute('stroke',T.brd);
                                                                                                            document.getElementById('toastRect').setAttribute('fill',T.tBg);
                                                                                                            document.getElementById('toastRect').setAttribute('stroke',T.tBrd);
                                                                                                            var ov=document.getElementById('modalOverlay'),rects=ov.querySelectorAll('rect');
                                                                                                            if(rects[0])rects[0].setAttribute('fill',T.bg);
                                                                                                            if(rects[1]){rects[1].setAttribute('fill',T.panel);rects[1].setAttribute('stroke',T.brd);}
                                                                                                            document.getElementById('modalMsg').setAttribute('fill',T.dim);
                                                                                                            document.getElementById('easter42').setAttribute('fill',isDark?'#161b22':'#e2e8f0');
                                                                                                            var gl=document.getElementById('gridLines');gl.setAttribute('opacity',T.gOp);
                                                                                                            var glLines=gl.getElementsByTagName('line');for(var i=0;i<glLines.length;i++)glLines[i].setAttribute('stroke',T.gCol);
                                                                                                                document.getElementById('themeIcon').textContent=isDark?'☀':'☾';
                                                                                                                var btns=document.getElementById('btnBar').querySelectorAll('.tbtn rect');
                                                                                                                for(var j=0;j<btns.length;j++){btns[j].setAttribute('fill',T.panel);btns[j].setAttribute('stroke',T.brd);}
                                                                                                                    var btxts=document.getElementById('btnBar').querySelectorAll('.tbtn text');
                                                                                                                    for(var k=0;k<btxts.length;k++){if(btxts[k].id!=='themeIcon')btxts[k].setAttribute('fill',T.dim);}
                                                                                                                        if(legendVisible)document.getElementById('btnLeg').setAttribute('class','tbtn tbtn-active');
                                                                                                                        else document.getElementById('btnLeg').removeAttribute('class');
                                                                                                                        }

                                                                                                                        var isDrag=false,dragF=null,dragSY=0,dragSA=0;
                                                                                                                        function findH(nd){while(nd&&nd.nodeType===1){if(nd.getAttribute&&nd.getAttribute('class')==='handle')return nd;nd=nd.parentNode;}return null;}
                                                                                                                        function findNID(nd){while(nd&&nd.nodeType===1){if(nd.getAttribute&&nd.getAttribute('data-nid'))return nd.getAttribute('data-nid');nd=nd.parentNode;}return null;}
                                                                                                                        function startDrag(ev){
                                                                                                                        if(curModal)return;var nd=findH(ev.target);if(!nd)return;ev.preventDefault();
                                                                                                                        var fid=nd.getAttribute('data-fid'),f=null;for(var i=0;i<flows.length;i++)if(flows[i].id===fid){f=flows[i];break;}
                                                                                                                            if(!f)return;var hasSib=false;for(var j=0;j<flows.length;j++)if(flows[j].from===f.from&&flows[j].id!==f.id){hasSib=true;break;}
                                                                                                                                if(!hasSib)return;isDrag=true;dragF=fid;dragSY=ev.clientY;dragSA=f.amount;
                                                                                                                                document.getElementById('modeText').textContent='MODE SCULPTURE — '+gR(f.from).name+' → '+gE(f.to).name;
                                                                                                                                document.getElementById('modeBadge').setAttribute('opacity','1');render();
                                                                                                                                }
                                                                                                                                function moveDrag(ev){
                                                                                                                                if(!isDrag)return;ev.preventDefault();
                                                                                                                                var f=null;for(var i=0;i<flows.length;i++)if(flows[i].id===dragF){f=flows[i];break;}if(!f)return;
                                                                                                                                    var dy=dragSY-ev.clientY,da=dy/SCALE,src=gR(f.from),sib=[];
                                                                                                                                    for(var j=0;j<flows.length;j++)if(flows[j].from===f.from&&flows[j].id!==f.id)sib.push(flows[j]);
                                                                                                                                        var mxA=src.amount-sib.length*MIN_FLOW,na=Math.max(MIN_FLOW,Math.min(dragSA+da,mxA));
                                                                                                                                        var rem=src.amount-na,ost=0;for(var k=0;k<sib.length;k++)ost+=sib[k].amount;
                                                                                                                                            if(ost>0)for(var m=0;m<sib.length;m++)sib[m].amount=rem*(sib[m].amount/ost);
                                                                                                                                                var def=0;for(var n=0;n<sib.length;n++)if(sib[n].amount<MIN_FLOW){def+=MIN_FLOW-sib[n].amount;sib[n].amount=MIN_FLOW;}
                                                                                                                                                        if(def>0){var adj=[],at=0;for(var p=0;p<sib.length;p++)if(sib[p].amount>MIN_FLOW){adj.push(sib[p]);at+=sib[p].amount-MIN_FLOW;}
                                                                                                                                                            if(at>0)for(var q=0;q<adj.length;q++)adj[q].amount-=def*((adj[q].amount-MIN_FLOW)/at);}
                                                                                                                                                                f.amount=na;var my=fpMY(f),mx2=fpMX(f),ad=na-dragSA,gc=ad>=0?'#34d399':'#f87171';
                                                                                                                                                                eG.innerHTML='<line x1="'+f.x0+'" y1="'+my+'" x2="'+f.x1+'" y2="'+my+'" stroke="'+gc+'" stroke-width=".6" stroke-dasharray="5,5" opacity=".4"/><text x="'+(mx2+14)+'" y="'+(my-8)+'" fill="'+gc+'" font-size="11" font-weight="700">'+(ad>=0?'+':'')+fmt(ad)+' M€</text>';
                                                                                                                                                                eG.setAttribute('opacity','1');computeLayout();render();
                                                                                                                                                                }
                                                                                                                                                                function endDrag(){
                                                                                                                                                                if(!isDrag)return;isDrag=false;dragF=null;
                                                                                                                                                                eG.setAttribute('opacity','0');document.getElementById('modeBadge').setAttribute('opacity','0');
                                                                                                                                                                computeLayout();render();
                                                                                                                                                                }
                                                                                                                                                                function handleNodeClick(ev){
                                                                                                                                                                if(curModal)return;var nid=findNID(ev.target);
                                                                                                                                                                if(nid){isolatedNode=(isolatedNode===nid)?null:nid;}
                                                                                                                                                                else if(isolatedNode){isolatedNode=null;}
                                                                                                                                                                render();
                                                                                                                                                                }

                                                                                                                                                                function showTT(ev){
                                                                                                                                                                if(isDrag||curModal||wasDragged){hideTT();return;}
                                                                                                                                                                var nd=ev.target;while(nd&&nd.nodeType===1){var cls=nd.getAttribute?nd.getAttribute('class'):'';if(cls&&(cls.indexOf('flow-path')>=0||cls==='handle'))break;nd=nd.parentNode;}
                                                                                                                                                                if(!nd||!nd.getAttribute){hideTT();return;}var fid=nd.getAttribute('data-fid');if(!fid){hideTT();return;}
                                                                                                                                                                var f=null;for(var i=0;i<flows.length;i++)if(flows[i].id===fid){f=flows[i];break;}if(!f)return;
                                                                                                                                                                    var src=gR(f.from),tgt=gE(f.to),svg=document.documentElement,pt=svg.createSVGPoint();
                                                                                                                                                                    pt.x=ev.clientX;pt.y=ev.clientY;var ctm=svg.getScreenCTM();if(!ctm)return;
                                                                                                                                                                    var sp=pt.matrixTransform(ctm.inverse()),tx=sp.x,ty=sp.y-52;if(ty<10)ty=sp.y+20;
                                                                                                                                                                        var sp2=(f.amount/src.amount*100).toFixed(1).replace('.',',');
                                                                                                                                                                        eTT.innerHTML='<rect x="'+(tx-100)+'" y="'+(ty-15)+'" width="200" height="50" rx="6" fill="'+T.tBg+'" stroke="'+T.brd+'" stroke-width="1"/>'
                                                                                                                                                                        +'<text x="'+tx+'" y="'+(ty-1)+'" text-anchor="middle" fill="'+T.fg+'" font-size="10" font-weight="600">'+esc(src.name)+' → '+esc(tgt.name)+'</text>'
                                                                                                                                                                        +'<text x="'+tx+'" y="'+(ty+13)+'" text-anchor="middle" fill="#f0b429" font-size="11.5" font-weight="700">'+fmt(f.amount)+' M€</text>'
                                                                                                                                                                        +'<text x="'+tx+'" y="'+(ty+26)+'" text-anchor="middle" fill="'+T.dim+'" font-size="9">'+sp2+' % de la source</text>';
                                                                                                                                                                        eTT.setAttribute('opacity','1');
                                                                                                                                                                        }
                                                                                                                                                                        function hideTT(){eTT.setAttribute('opacity','0');}
                                                                                                                                                                        function notify(msg){
                                                                                                                                                                        document.getElementById('toastText').textContent=msg;
                                                                                                                                                                        var ts=document.getElementById('toast');ts.setAttribute('opacity','1');clearTimeout(nTimer);nTimer=setTimeout(function(){ts.setAttribute('opacity','0');},2800);
                                                                                                                                                                        }

                                                                                                                                                                        /* ═══════ POPUP MODAL ═══════ */
                                                                                                                                                                        var POPCSS='*{box-sizing:border-box;margin:0;padding:0}body{background:#0d1117;color:#e6edf3;font-family:Segoe UI,system-ui,sans-serif;padding:20px 24px}'
                                                                                                                                                                        +'h2{color:#f0b429;font-size:18px;margin-bottom:16px;letter-spacing:1px}'
                                                                                                                                                                        +'h3{color:#f0b429;font-size:13px;font-weight:700;margin:16px 0 8px;padding-bottom:4px;border-bottom:1px solid #30363d;letter-spacing:.5px}'
                                                                                                                                                                        +'.row{display:flex;align-items:center;gap:8px;margin:5px 0}.dot{width:10px;height:10px;border-radius:50%;flex-shrink:0;transition:background .2s}'
                                                                                                                                                                        +'input,select,textarea{background:#0d1117;border:1px solid #30363d;color:#e6edf3;padding:5px 8px;border-radius:4px;font-size:12px;font-family:inherit}'
                                                                                                                                                                        +'input:focus,select:focus,textarea:focus{border-color:#f0b429;outline:none}'
                                                                                                                                                                        +'input[type=text]{flex:1}input[type=number]{text-align:right;width:100px}'
                                                                                                                                                                        +'input[type=color]{width:34px;height:30px;padding:2px;cursor:pointer;border-radius:6px;background:#0d1117;border:1px solid #30363d;flex-shrink:0}'
                                                                                                                                                                        +'input[type=color]::-webkit-color-swatch-wrapper{padding:1px}input[type=color]::-webkit-color-swatch{border-radius:4px;border:none}'
                                                                                                                                                                        +'input[type=color]::-moz-color-swatch{border-radius:4px;border:none}'
                                                                                                                                                                        +'.unit{color:#8b949e;font-size:10px;width:28px}.amt{color:#8b949e;font-size:10px;width:90px;text-align:right}'
                                                                                                                                                                        +'.frow{display:flex;align-items:center;gap:6px;margin:3px 0}.farrow{color:#8b949e;font-size:13px;width:16px;text-align:center}'
                                                                                                                                                                        +'.ftgt{width:140px;color:#e6edf3;font-size:11px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}'
                                                                                                                                                                        +'.fpct{color:#8b949e;font-size:10px;width:50px;text-align:right}'
                                                                                                                                                                        +'.note{color:#8b949e;font-size:10px;font-style:italic;margin:8px 0;padding:6px 10px;background:#0d1117;border-radius:4px;border:1px solid #21262d}'
                                                                                                                                                                        +'.warn{color:#fbbf24}.err{color:#f87171;display:none;margin:6px 0;padding:6px 10px;background:#1c1008;border-radius:4px;border:1px solid #f8717140}'
                                                                                                                                                                        +'.btns{display:flex;gap:12px;justify-content:center;margin:20px 0 10px;padding-top:14px;border-top:1px solid #30363d;flex-wrap:wrap}'
                                                                                                                                                                        +'.ba{background:#f0b429;color:#0d1117;border:none;padding:8px 24px;border-radius:6px;font-weight:700;cursor:pointer;font-size:13px}'
                                                                                                                                                                        +'.ba:hover{background:#fbbf24}.bc{background:#21262d;color:#8b949e;border:1px solid #30363d;padding:8px 24px;border-radius:6px;font-weight:600;cursor:pointer;font-size:13px}'
                                                                                                                                                                        +'.bc:hover{background:#30363d;color:#e6edf3}.msg{color:#34d399;font-size:11px;min-height:16px}';

                                                                                                                                                                        function showModal(type){
                                                                                                                                                                        if(popupWin&&!popupWin.closed){try{popupWin.close();}catch(e){}}
                                                                                                                                                                        curModal=type;
                                                                                                                                                                        document.getElementById('modalOverlay').setAttribute('opacity','1');
                                                                                                                                                                        document.getElementById('modalOverlay').style.pointerEvents='all';
                                                                                                                                                                        document.getElementById('modalMsg').textContent=type==='params'?'Fenêtre Paramètres ouverte...':'Fenêtre Import/Export ouverte...';
                                                                                                                                                                        popupWin=window.open('','budgetPopup','width=820,height=720,scrollbars=yes,resizable=yes');
                                                                                                                                                                        if(!popupWin){notify('Popup bloqué — autorisez les popups');hideModal();return;}
                                                                                                                                                                        popupWin.document.open();popupWin.document.write(type==='params'?buildParamsPopup():buildIOPopup());popupWin.document.close();
                                                                                                                                                                        clearInterval(popupTimer);
                                                                                                                                                                        popupTimer=setInterval(function(){try{if(popupWin.closed){clearInterval(popupTimer);hideModal();}}catch(e){clearInterval(popupTimer);hideModal();}},400);
                                                                                                                                                                        }
                                                                                                                                                                        function hideModal(){
                                                                                                                                                                        document.getElementById('modalOverlay').setAttribute('opacity','0');
                                                                                                                                                                        document.getElementById('modalOverlay').style.pointerEvents='none';
                                                                                                                                                                        curModal=null;if(popupWin&&!popupWin.closed){try{popupWin.close();}catch(e){}}popupWin=null;clearInterval(popupTimer);
                                                                                                                                                                        }

                                                                                                                                                                        function buildParamsPopup(){
                                                                                                                                                                        var h='<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Paramètres</title><style>'+POPCSS+'</style></head><body>';
                                                                                                                                                                                    h+='<h2>PARAMÈTRES DU BUDGET</h2><h3>TITRE DU DIAGRAMME</h3>';
                                                                                                                                                                                    h+='<input type="text" id="diagramTitle" value="'+esc(diagramTitle)+'" style="width:100%;font-size:14px;font-weight:600;text-align:center">';
                                                                                                                                                                                        h+='<h3>RECETTES</h3>';
                                                                                                                                                                                        for(var i=0;i<revenues.length;i++){var r=revenues[i];
                                                                                                                                                                                            h+='<div class="row"><span class="dot" id="dotR'+i+'" style="background:'+r.color+'"></span>';
                                                                                                                                                                                                h+='<input type="text" id="rn'+i+'" value="'+esc(r.name)+'"><input type="number" id="ra'+i+'" value="'+r.amount+'" min="0" step="50"><span class="unit">M€</span>';
                                                                                                                                                                                                        h+='<input type="color" id="rc'+i+'" value="'+r.color+'" onchange="syncDot(\'R'+i+'\',this.value)"></div>';}
                                                                                                                                                                                                        h+='<h3>DÉPENSES (noms — montants calculés)</h3>';
                                                                                                                                                                                                        for(var j=0;j<expenses.length;j++){var e=expenses[j];
                                                                                                                                                                                                            h+='<div class="row"><span class="dot" id="dotE'+j+'" style="background:'+e.color+'"></span>';
                                                                                                                                                                                                                h+='<input type="text" id="en'+j+'" value="'+esc(e.name)+'"><span class="amt">'+fmt(e.amount)+' M€</span>';
                                                                                                                                                                                                                    h+='<input type="color" id="ec'+j+'" value="'+e.color+'" onchange="syncDot(\'E'+j+'\',this.value)"></div>';}
                                                                                                                                                                                                                    h+='<h3>FLUX — Source :</h3><select id="flowSrcSel" style="width:100%;margin-bottom:6px">';
                                                                                                                                                                                                                        for(var k=0;k<revenues.length;k++)h+='<option value="'+k+'">'+esc(revenues[k].name)+' ('+fmt(revenues[k].amount)+' M€)</option>';
                                                                                                                                                                                                                            h+='</select><div id="flowsEd"></div>';
                                                                                                                                                                                                                        h+='<div class="note">Les flux seront proportionnellement ajustés au montant de la recette source.</div>';
                                                                                                                                                                                                                        h+='<div class="btns"><button class="bc" onclick="window.close()">Annuler</button><button class="ba" onclick="doApply()">Appliquer</button></div>';
                                                                                                                                                                                                                        h+='<div class="msg" id="pMsg"></div>';
                                                                                                                                                                                                                        h+='<script>function syncDot(id,c){var d=document.getElementById("dot"+id);if(d)d.style.background=c;}';
                                                                                                                                                                                                                            h+='function doApply(){var d={};var all=document.querySelectorAll("input[id]");for(var i=0;i<all.length;i++)d[all[i].id]=all[i].value;';
                                                                                                                                                                                                                                h+='window.opener.applyPopupData(d,"params");window.close();}';
                                                                                                                                                                                                                                h+='document.getElementById("flowSrcSel").onchange=function(){window.opener.renderPopupFlows();};';
                                                                                                                                                                                                                                h+='setTimeout(function(){window.opener.renderPopupFlows();},100);<\/script></body></html>';
                                                                                                                                                                                                                            return h;
                                                                                                                                                                                                                            }

                                                                                                                                                                                                                            function renderPopupFlows(){
                                                                                                                                                                                                                            if(!popupWin||popupWin.closed)return;
                                                                                                                                                                                                                            try{var doc=popupWin.document,sel=doc.getElementById('flowSrcSel'),c=doc.getElementById('flowsEd');if(!sel||!c)return;
                                                                                                                                                                                                                            var si=parseInt(sel.value),src=revenues[si],fl=[],tot=0;
                                                                                                                                                                                                                            for(var i=0;i<flows.length;i++)if(flows[i].from===src.id){fl.push(flows[i]);tot+=flows[i].amount;}
                                                                                                                                                                                                                                var h='<div style="font-size:10px;color:#8b949e;margin:4px 0">Total : <b>'+fmt(tot)+'</b> M€ / <b>'+fmt(src.amount)+'</b> M€';
                                                                                                                                                                                                                                    if(Math.abs(tot-src.amount)>1)h+=' <span class="warn">(ajustement auto)</span>';h+='</div>';
                                                                                                                                                                                                                                for(var j=0;j<fl.length;j++){var f=fl[j],tgt=gE(f.to),pct=tot>0?(f.amount/tot*100).toFixed(1).replace('.',','):'0,0';
                                                                                                                                                                                                                                    h+='<div class="frow"><span class="farrow">\u2192</span><span class="dot" style="background:'+tgt.color+'"></span>';
                                                                                                                                                                                                                                        h+='<span class="ftgt">'+esc(tgt.name)+'</span><input type="number" id="fa_'+f.id+'" value="'+Math.round(f.amount)+'" min="0" step="10">';
                                                                                                                                                                                                                                            h+='<span class="unit">M€</span><span class="fpct">'+pct+' %</span></div>';}
                                                                                                                                                                                                                                        c.innerHTML=h;}catch(e){}
                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                        function applyPopupData(d,type){
                                                                                                                                                                                                                                        if(type==='params'){
                                                                                                                                                                                                                                        if(d['diagramTitle']){diagramTitle=d['diagramTitle'];document.getElementById('mainTitle').textContent=diagramTitle;}
                                                                                                                                                                                                                                        for(var i=0;i<revenues.length;i++){if(d['rn'+i])revenues[i].name=d['rn'+i];var v=parseFloat(d['ra'+i]);if(!isNaN(v)&&v>=0)revenues[i].amount=v;if(d['rc'+i])revenues[i].color=d['rc'+i];}
                                                                                                                                                                                                                                            for(var j=0;j<expenses.length;j++){if(d['en'+j])expenses[j].name=d['en'+j];if(d['ec'+j])expenses[j].color=d['ec'+j];}
                                                                                                                                                                                                                                                for(var k=0;k<flows.length;k++){var fv=parseFloat(d['fa_'+flows[k].id]);if(!isNaN(fv)&&fv>=0)flows[k].amount=fv;}
                                                                                                                                                                                                                                                    for(var m=0;m<revenues.length;m++){var src=revenues[m],of=[],tot=0;
                                                                                                                                                                                                                                                        for(var n=0;n<flows.length;n++)if(flows[n].from===src.id){of.push(flows[n]);tot+=flows[n].amount;}
                                                                                                                                                                                                                                                        if(tot>0&&Math.abs(tot-src.amount)>.5){var ratio=src.amount/tot;for(var p=0;p<of.length;p++)of[p].amount*=ratio;}
                                                                                                                                                                                                                                                        else if(tot===0&&src.amount>0){var each=src.amount/Math.max(of.length,1);for(var q=0;q<of.length;q++)of[q].amount=each;}}
                                                                                                                                                                                                                                                        recomp();saveInit();computeLayout();render();hideModal();notify('Paramètres appliqués');
                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                        function buildIOPopup(){
                                                                                                                                                                                                                                                        var h='<!DOCTYPE html><html><head><meta charset="UTF-8"><title>I/O</title><style>'+POPCSS+'</style></head><body>';
                                                                                                                                                                                                                                                        h+='<h2>IMPORT / EXPORT</h2><h3>Données JSON :</h3>';
                                                                                                                                                                                                                                                        h+='<textarea id="ioTA" style="width:100%;height:420px;background:#0d1117;border:1px solid #30363d;color:#e6edf3;border-radius:6px;padding:10px;font-family:monospace;font-size:11px;resize:vertical"></textarea>';
                                                                                                                                                                                                                                                        h+='<div class="err" id="ioErr"></div><div class="msg" id="ioMsg"></div>';
                                                                                                                                                                                                                                                        h+='<div class="btns"><button class="bc" onclick="window.close()">Annuler</button><button class="bc" onclick="doCopy()">\uD83D\uDCCB Copier</button><button class="bc" onclick="doDL()">\uD83D\uDCBE .json</button><button class="ba" onclick="doRefresh()">Actualiser</button><button class="ba" onclick="doImport()">Importer</button></div>';
                                                                                                                                                                                                                                                        h+='<div class="note">Titre, couleurs et données inclus.</div>';
                                                                                                                                                                                                                                                        h+='<script>var O=window.opener;function doRefresh(){document.getElementById("ioTA").value=O.exportJSON();document.getElementById("ioErr").style.display="none";showMsg("OK");}';
                                                                                                                                                                                                                                                        h+='function doCopy(){var t=document.getElementById("ioTA");if(navigator.clipboard&&navigator.clipboard.writeText)navigator.clipboard.writeText(t.value).then(function(){showMsg("Copi\u00E9 !");});else{t.select();document.execCommand("copy");showMsg("Copi\u00E9 !");}}';
                                                                                                                                                                                                                                                        h+='function doDL(){var t=document.getElementById("ioTA");var b=new Blob([t.value],{type:"application/json"});var u=URL.createObjectURL(b);var a=document.createElement("a");a.href=u;a.download="budget-data.json";document.body.appendChild(a);a.click();document.body.removeChild(a);setTimeout(function(){URL.revokeObjectURL(u);},1000);showMsg("T\u00E9l\u00E9charg\u00E9");}';
                                                                                                                                                                                                                                                        h+='function doImport(){var t=document.getElementById("ioTA");var e=document.getElementById("ioErr");e.style.display="none";try{var d=JSON.parse(t.value);if(!d.revenues||!d.expenses||!d.flows)throw new Error("Il faut revenues, expenses, flows");if(!Array.isArray(d.revenues)||!Array.isArray(d.expenses)||!Array.isArray(d.flows))throw new Error("Tableaux requis");O.applyImportData(d);window.close();}catch(err){e.textContent="Erreur : "+err.message;e.style.display="block";}}';
                                                                                                                                                                                                                                                        h+='function showMsg(t){var m=document.getElementById("ioMsg");m.textContent=t;setTimeout(function(){m.textContent="";},2000);}setTimeout(doRefresh,100);<\/script></body></html>';
                                                                                                                                                                                                                                                    return h;
                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                    function exportJSON(){return JSON.stringify({title:diagramTitle,revenues:revenues.map(function(r){return{name:r.name,amount:r.amount,color:r.color};}),expenses:expenses.map(function(e){return{name:e.name,color:e.color};}),flows:flows.map(function(f){return{from:f.from,to:f.to,amount:Math.round(f.amount*100)/100};})},null,2);}

                                                                                                                                                                                                                                                    function applyImportData(d){
                                                                                                                                                                                                                                                    if(d.title){diagramTitle=d.title;document.getElementById('mainTitle').textContent=diagramTitle;}
                                                                                                                                                                                                                                                    for(var i=0;i<d.revenues.length&&i<revenues.length;i++){if(d.revenues[i].name)revenues[i].name=d.revenues[i].name;if(typeof d.revenues[i].amount==='number')revenues[i].amount=d.revenues[i].amount;if(d.revenues[i].color)revenues[i].color=d.revenues[i].color;}
                                                                                                                                                                                                                                                        for(var j=0;j<d.expenses.length&&j<expenses.length;j++){if(d.expenses[j].name)expenses[j].name=d.expenses[j].name;if(d.expenses[j].color)expenses[j].color=d.expenses[j].color;}
                                                                                                                                                                                                                                                        for(var k=0;k<d.flows.length&&k<flows.length;k++)if(typeof d.flows[k].amount==='number')flows[k].amount=d.flows[k].amount;
                                                                                                                                                                                                                                                        for(var m=0;m<revenues.length;m++){var src=revenues[m],of=[],tot=0;for(var n=0;n<flows.length;n++)if(flows[n].from===src.id){of.push(flows[n]);tot+=flows[n].amount;}
                                                                                                                                                                                                                                                        if(tot>0&&Math.abs(tot-src.amount)>.5){var ratio=src.amount/tot;for(var p=0;p<of.length;p++)of[p].amount*=ratio;}
                                                                                                                                                                                                                                                        else if(tot===0&&src.amount>0){var each=src.amount/Math.max(of.length,1);for(var q=0;q<of.length;q++)of[q].amount=each;}}
                                                                                                                                                                                                                                                        recomp();saveInit();computeLayout();render();hideModal();notify('Données importées');
                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                        function saveSVG(){
                                                                                                                                                                                                                                                        try{computeLayout();var s='<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1400 950" style="background:'+T.bg+';font-family:Segoe UI,system-ui,sans-serif">\n';
                                                                                                                                                                                                                                                        s+='<defs><linearGradient id="goldL" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="#f0b429" stop-opacity="0"/><stop offset="50%" stop-color="#f0b429" stop-opacity=".6"/><stop offset="100%" stop-color="#f0b429" stop-opacity="0"/></linearGradient></defs>\n';
                                                                                                                                                                                                                                                        s+='<rect width="1400" height="950" fill="'+T.bg+'"/>\n';
                                                                                                                                                                                                                                                        s+='<g opacity="'+T.gOp+'" stroke="'+T.gCol+'" stroke-width=".5"><line x1="215" y1="82" x2="215" y2="710"/><line x1="700" y1="82" x2="700" y2="710"/><line x1="1185" y1="82" x2="1185" y2="710"/><line x1="25" y1="82" x2="1375" y2="82"/><line x1="25" y1="710" x2="1375" y2="710"/></g>\n';
                                                                                                                                                                                                                                                        s+='<text x="700" y="30" text-anchor="middle" fill="'+T.fg+'" font-size="21" font-weight="700" letter-spacing="2">'+esc(diagramTitle)+'</text>\n';
                                                                                                                                                                                                                                                        s+='<line x1="460" y1="40" x2="940" y2="40" stroke="url(#goldL)" stroke-width="1.5"/>\n';
                                                                                                                                                                                                                                                        for(var i=0;i<flows.length;i++){var f=flows[i],src=gR(f.from);s+='<path d="'+fpD(f)+'" fill="'+src.color+'" opacity="'+T.fOp+'"/>\n';}
                                                                                                                                                                                                                                                        for(var j=0;j<revenues.length;j++){var r=revenues[j],fs=r.h>55?11:r.h>38?9.5:8;
                                                                                                                                                                                                                                                        s+='<rect x="'+r.x+'" y="'+r.y+'" width="'+r.w+'" height="'+r.h+'" rx="4" fill="'+r.color+'" fill-opacity="'+T.nFill+'" stroke="'+r.color+'" stroke-width="1.2" stroke-opacity="'+T.nStr+'"/>\n';
                                                                                                                                                                                                                                                        s+='<text x="'+(r.x+r.w/2)+'" y="'+(r.y+r.h/2-(r.h>55?7:0))+'" text-anchor="middle" fill="'+r.color+'" font-size="'+fs+'" font-weight="600">'+esc(r.name)+'</text>\n';
                                                                                                                                                                                                                                                        if(r.h>55)s+='<text x="'+(r.x+r.w/2)+'" y="'+(r.y+r.h/2+7)+'" text-anchor="middle" fill="'+T.fg+'" font-size="'+(fs-1)+'" opacity=".8">'+fmt(r.amount)+' M€</text>\n';}
                                                                                                                                                                                                                                                        for(var k=0;k<expenses.length;k++){var e=expenses[k],fs2=e.h>55?11:e.h>38?9.5:8;
                                                                                                                                                                                                                                                        s+='<rect x="'+e.x+'" y="'+e.y+'" width="'+e.w+'" height="'+e.h+'" rx="4" fill="'+e.color+'" fill-opacity="'+T.nFill+'" stroke="'+e.color+'" stroke-width="1.2" stroke-opacity="'+T.nStr+'"/>\n';
                                                                                                                                                                                                                                                        s+='<text x="'+(e.x+e.w/2)+'" y="'+(e.y+e.h/2-(e.h>55?7:0))+'" text-anchor="middle" fill="'+e.color+'" font-size="'+fs2+'" font-weight="600">'+esc(e.name)+'</text>\n';
                                                                                                                                                                                                                                                        if(e.h>55)s+='<text x="'+(e.x+e.w/2)+'" y="'+(e.y+e.h/2+7)+'" text-anchor="middle" fill="'+T.fg+'" font-size="'+(fs2-1)+'" opacity=".8">'+fmt(e.amount)+' M€</text>\n';}
                                                                                                                                                                                                                                                        s+='<rect x="20" y="725" width="1360" height="215" rx="10" fill="'+T.panel+'" stroke="'+T.brd+'" stroke-width="1"/>\n';
                                                                                                                                                                                                                                                        s+='<text x="700" y="744" text-anchor="middle" fill="'+T.dim+'" font-size="10.5" font-weight="600" letter-spacing="1.5">SOLDES INTERMÉDIAIRES PAR SERVICE</text>\n';
                                                                                                                                                                                                                                                        s+='<line x1="40" y1="752" x2="1360" y2="752" stroke="'+T.brd+'" stroke-width=".5"/>\n';
                                                                                                                                                                                                                                                        var mx=1;for(var m=0;m<expenses.length;m++)if(expenses[m].amount>mx)mx=expenses[m].amount;
                                                                                                                                                                                                                                                        for(var n=0;n<expenses.length;n++){var ex=expenses[n],bw=Math.max(2,ex.amount/mx*520),yb=760+n*24;
                                                                                                                                                                                                                                                        s+='<text x="40" y="'+(yb+10)+'" fill="'+ex.color+'" font-size="10.5" font-weight="600">'+esc(ex.name)+'</text>\n';
                                                                                                                                                                                                                                                        s+='<rect x="220" y="'+(yb-2)+'" width="520" height="13" rx="3" fill="'+T.barBg+'"/>\n';
