                                                                                                                                                                                                                                                    function resetAll(){
                                                                                                                                                                                                                                                    var rn=['Impôts sur le revenu','TVA','Taxes locales','Emprunts','Subventions État'],ra=[3200,2800,1200,800,500],rc=['#fbbf24','#f59e0b','#d97706','#b45309','#92400e'];
