                                                                                                                                                                                                                                                        eS=document.getElementById('summaryGroup');eLeg=document.getElementById('legendGroup');
                                                                                                                                                                                                                                                        recomp();saveInit();computeLayout();applyTheme();render();
                                                                                                                                                                                                                                                        document.getElementById('btnBar').addEventListener('click',function(ev){
                                                                                                                                                                                                                                                        var nd=ev.target;while(nd&&nd.nodeType===1){if(nd.getAttribute&&nd.getAttribute('data-action'))break;nd=nd.parentNode;}
                                                                                                                                                                                                                                                        if(!nd||!nd.getAttribute)return;var a=nd.getAttribute('data-action');
                                                                                                                                                                                                                                                        if(a==='params')showModal('params');else if(a==='io')showModal('io');else if(a==='save')saveSVG();else if(a==='reset')resetAll();
                                                                                                                                                                                                                                                        else if(a==='theme'){isDark=!isDark;T=isDark?darkT:lightT;applyTheme();render();notify(isDark?'Thème sombre':'Thème clair');}
                                                                                                                                                                                                                                                        else if(a==='legend'){legendVisible=!legendVisible;applyTheme();render();notify(legendVisible?'Légende affichée':'Légende masquée');}
                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                        eLeg.addEventListener('click',function(ev){
                                                                                                                                                                                                                                                        var nd=ev.target;while(nd&&nd.nodeType===1){if(nd.getAttribute&&nd.getAttribute('data-nid')){var nid=nd.getAttribute('data-nid');isolatedNode=(isolatedNode===nid)?null:nid;render();return;}nd=nd.parentNode;}
                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                        document.getElementById('mainTitle').addEventListener('dblclick',function(){showModal('params');});
