                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                        document.documentElement.addEventListener('mousedown',function(ev){mouseSX=ev.clientX;mouseSY=ev.clientY;wasDragged=false;startDrag(ev);});
                                                                                                                                                                                                                                                        document.addEventListener('mousemove',function(ev){if(Math.abs(ev.clientX-mouseSX)>3||Math.abs(ev.clientY-mouseSY)>3)wasDragged=true;moveDrag(ev);showTT(ev);});
                                                                                                                                                                                                                                                        document.addEventListener('mouseup',function(ev){if(!wasDragged&&!isDrag)handleNodeClick(ev);endDrag();});
                                                                                                                                                                                                                                                        document.documentElement.addEventListener('mouseleave',hideTT);
                                                                                                                                                                                                                                                        document.documentElement.addEventListener('touchstart',function(ev){
                                                                                                                                                                                                                                                        if(ev.touches.length!==1||curModal)return;var t=ev.touches[0],el=document.elementFromPoint(t.clientX,t.clientY);
                                                                                                                                                                                                                                                        startDrag({target:el,clientY:t.clientY,preventDefault:function(){ev.preventDefault();}});
                                                                                                                                                                                                                                                        },{passive:false});
                                                                                                                                                                                                                                                        document.addEventListener('touchmove',function(ev){
                                                                                                                                                                                                                                                        if(isDrag&&ev.touches.length===1)moveDrag({clientY:ev.touches[0].clientY,preventDefault:function(){ev.preventDefault();}});
                                                                                                                                                                                                                                                        },{passive:false});
                                                                                                                                                                                                                                                        document.addEventListener('touchend',endDrag);
                                                                                                                                                                                                                                                        })();
